mapper.select:
SELECT ID, EXTERNAL_COMPANY_ID, PRINCIPAL, PHONE, REPAIR_TYPE, REMARK, CONTRACT_DATE_START, CONTRACT_DATE_END, DELETED, CREATED_USER, CREATED_TIME, MODIFIED_USER, MODIFIED_TIME, EXTERNAL_COMPANY_CODE, UNIT_NAME, COMPANY_ID, USER_ORG_ID, SERVICE_COMPANIES, TYPE FROM E_M_EQUIP_REPAIR_CONTRACT where 1=1
and EXTERNAL_COMPANY_CODE like #{externalCompanyCodeLike}
and UNIT_NAME like #{unitNameLike}
order by CREATED_TIME DESC
